class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int[] gcd = new int[n];
        gcd[0] = nums[0];
        for (int i = 1; i < n; i++) {
            gcd[i] = gcd(gcd[i - 1], nums[i]);
        }
        int res = 0;
        int cnt = 0;
        for (int i = n - 1; i >= 0; i--) {
            if (gcd[i] >= 2) {
                cnt++;
            } else {
                cnt = 0;
            }
            res = Math.max(res, Math.min(cnt, maxC + 1));
        }
        return res;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
